function main() {
  const inputArg = process.argv[2];
  let inputFile;

  if (inputArg) {
    inputFile = path.resolve(inputArg);
  } else {
    const latest = findLatestInput();
    if (!latest) {
      console.error('未找到输入数据文件。请指定文件路径：node preprocess_cdp.js <data-file>');
      process.exit(1);
    }
    inputFile = path.join(DATA_DIR, latest);
  }

  if (!fs.existsSync(inputFile)) {
    console.error(`文件不存在: ${inputFile}`);
    process.exit(1);
  }

  console.log(`读取: ${path.basename(inputFile)}`);
  const raw = JSON.parse(fs.readFileSync(inputFile, 'utf-8'));
  const result = processAll(raw);

  const ts = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);
  const outFile = path.join(DATA_DIR, `cleaned_${ts}.json`);
  fs.writeFileSync(outFile, JSON.stringify(result, null, 2), 'utf-8');

  console.log(`输出: ${path.basename(outFile)}`);
  console.log(`统计: ${result.stats.total} 个客户`);
  console.log(`  系统消息检测: ${result.stats.systemMsgDetected}`);
  console.log(`  需要往前看: ${result.stats.needLookback}`);
  console.log(`  需要完整阅读(≥10条): ${result.stats.needFullRead}`);
  console.log(`  有产品选择: ${result.stats.hasProductSelection}`);
  console.log(`  有地址信息: ${result.stats.hasAddress}`);
  console.log(`  有问题标记: ${result.stats.hasIssues}`);
  console.log(`  沉默超90天: ${result.stats.silentOver90Days}`);
  console.log(`  沉默超30天: ${result.stats.silentOver30Days}`);

  if (result.stats.hasIssues > 0) {
    const issueList = result.customers.filter((c) => c._issues.length > 0);
    console.log(`\n标记有问题的客户（前10）:`);
    for (const c of issueList.slice(0, 10)) {
      console.log(`  - ${c.name}: ${c._issues.join('; ')}`);
    }
  }
}

main();

