// ====== 主处理函数 ======

function getCustomersFromData(data) {
  if (Array.isArray(data)) return data;
  if (data.customers) return data.customers;
  if (data.p0p1) return data.p0p1;
  if (data.results) return data.results;
  return [];
}

function processCustomer(customer) {
  const entry = { ...customer };
  const flags = {};
  const issues = [];

  const rawMsg = entry.latestMessageContent || '';
  const isSys = isSystemMessage(rawMsg);

  // 1. 系统消息检测
  flags.isLatestSystemMsg = isSys;
  if (isSys) {
    issues.push('latestMessageContent 是系统消息');
    // 尝试从消息列表中找真实消息
    if (Array.isArray(entry.messages)) {
      const real = findLatestRealMessage(entry.messages);
      if (real) {
        entry._replacedMessageContent = real.text || real.latestMessageContent || '';
        entry._replacedFromIndex = entry.messages.indexOf(real);
        flags.latestMsgReplaced = true;
      }
    }
  }

  // 2. 表情/单字检测
  const effectiveMsg = flags.latestMsgReplaced ? entry._replacedMessageContent : rawMsg;
  if (isEmojiOrSingleWord(effectiveMsg)) {
    flags.needLookback = true;
    issues.push('最后一条有效消息是表情/单字，需往前看');
  }

  // 3. 消息数统计
  const msgCount = entry.messageCount || (Array.isArray(entry.messages) ? entry.messages.length : 0);
  entry._computedMessageCount = msgCount;
  if (msgCount >= 10) {
    flags.needFullRead = true;
    issues.push(`消息数 ${msgCount} ≥ 10，必须逐条读取`);
  }

  // 4. 产品代码扫描
  const scanTargets = [effectiveMsg];
  if (Array.isArray(entry.messages)) {
    for (const m of entry.messages) {
      scanTargets.push(m.text || '');
    }
  }
  const allCodes = [];
  for (const t of scanTargets) {
    allCodes.push(...scanProductCodes(t));
  }
  const uniqueCodes = [...new Set(allCodes)];
  if (uniqueCodes.length > 0) {
    flags.hasProductSelection = true;
    entry._productCodes = uniqueCodes;
  }

  // 5. 地址关键词扫描
  if (scanAddressKeywords(effectiveMsg) || (Array.isArray(entry.messages) && entry.messages.some((m) => scanAddressKeywords(m.text || '')))) {
    flags.hasAddress = true;
  }

  // 6. 沉默天数
  const lastTime = entry.lastContactTime || entry.latestMessageTime;
  const silenceDays = calcSilenceDays(lastTime);
  entry._silenceDays = silenceDays;

  // 7. 消息方向
  if (Array.isArray(entry.messages)) {
    const dir = calcMessageDirection(entry.messages);
    if (dir) {
      entry._messageDirection = dir;
    }
  } else if (entry.latestMessageType) {
    entry._messageDirection = {
      total: msgCount || 1,
      latestDirection: entry.latestMessageType,
    };
  }

  // 8. 合并标记
  entry._flags = flags;
  entry._issues = issues;

  return entry;
}

function processAll(data) {
  const customers = getCustomersFromData(data);
  const cleaned = customers.map(processCustomer);

