function processCustomer(customer) {
  const entry = { ...customer };

  // ====== 字段标准化（兼容extract_cdp和全量客户分类两种格式） ======
  // extract_cdp 格式：{ name, timeStr, isUnread, message, daysAgo, ... }
  // 全量客户分类格式：{ name, latestMessageContent, lastContactTime, latestMessageType, ... }
  if (!entry.latestMessageContent && entry.message) {
    entry.latestMessageContent = entry.message;
  }
  if (!entry.latestMessageType) {
    // 从message方向推断：有unreadCount/msgFromCustomer推断
    entry.latestMessageType = entry.isUnread ? 'received' : 'send';
  }
  if (!entry.lastContactTime && !entry.latestMessageTime) {
    // extract_cdp的timeStr是"HH:MM"或"YYYY-M-D"格式
    if (entry.timeStr) {
      if (entry.timeStr.includes(':')) {
        // 今天的时间 → 用当前时间
        entry.lastContactTime = Date.now();
      } else {
        entry.lastContactTime = new Date(entry.timeStr).getTime();
      }
    }
  }
  // 如果extract_cdp已经计算了daysAgo，优先使用
  if (entry.daysAgo !== undefined && !entry._precomputedSilence) {
    entry._precomputedSilence = entry.daysAgo;
  }

