/**
 * 阶段0：数据预处理脚本
 * 输入：data/extracted_*.json 或 data/*全量客户分类.json（CDP 抓取原始数据）
 * 输出：data/cleaned_<timestamp>.json
 *
 * 处理内容：
 * - 检测 latestMessageContent 是否系统消息 → 标记并尝试替换
 * - 检测最后消息是否表情/单字 → 标记 needLookback
 * - 统计消息数 → 标记 needFullRead（≥10 条）
 * - 正则扫描产品代码和地址关键词 → 标记 hasProductSelection / hasAddress
 * - 计算沉默天数
 * - 统计消息方向（如有消息列表数据）
 */

const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, '..', 'data');

// ====== 系统消息模式（来自 business-rules.md） ======
const SYSTEM_MSG_PATTERNS = [
  /automatic reception will no longer intervene/i,
  /自动接待将不再触发/,
  /Marco大模型翻译/,
  /阿里国际Marco大模型翻译/,
  /买家有流失风险/,
  /Buyer has churn risk/,
  /一旦离开平台发生纠纷或欺诈/,
  /由于您介入该会话/,
  /Due to your intervention in this session/,
  /AI给您生成了一条回复建议/,
  /反馈/,
  /You have a visitor\. Follow up with them as soon as possible\./i,
  /This buyer has been pre-screened and has a clear request/i,
  /Since you have read the conversation/i,
];

// ====== 表情/单字模式 ======
const EMOJI_SINGLE_PATTERNS = [
  /^[\u{1F000}-\u{1FFFF}]+$/u,
  /^[\u{2600}-\u{27BF}]+$/u,
  /^[\u{FE00}-\u{FEFF}]+$/u,
  /^[\u{2702}-\u{27B0}]+$/u,
  /^[\u{1F600}-\u{1F64F}]+$/u,
  /^[\u{1F300}-\u{1F5FF}]+$/u,
  /^[\u{1F680}-\u{1F6FF}]+$/u,
  /^[\u{1F900}-\u{1F9FF}]+$/u,
  /^(ok|okay|yes|no|hi|hello|hey|thanks|thx|ty|bye|good|nice|wow)$/i,
  /^[\u{1F600}-\u{1FAFF}\u{2600}-\u{27BF}\u{1F300}-\u{1F5FF}\u{1F680}-\u{1F6FF}\u{1F900}-\u{1F9FF}\u{2700}-\u{27BF}]+$/u,
  /^\[图片\]$/, /^\[商品\]$/, /^\[表情\]$/,
];

// ====== 产品代码模式 ======
const PRODUCT_CODE_RE = /(?:CO|PO|BO|SO|MO|SKU)[-_\s]?\d{2,4}/gi;

// ====== 地址关键词 ======
const ADDRESS_KEYWORDS = [
  /address/i, /shipping/i, /delivery/i, /地址/, /收货/, /运送/,
  /street/i, /city/i, /country/i, /zip/i, /postal/i,
  /cameroon/i, /nigeria/i, /kenya/i, /ghana/i, /tanzania/i, /uganda/i, /zambia/i,
  /saudi/i, /uae/i, /dubai/i, /egypt/i, /sudan/i, /morocco/i, /algeria/i,
  /colombia/i, /brazil/i, /mexico/i, /peru/i, /chile/i,
  /cotonou/i, /lagos/i, /nairobi/i, /doha/i, /riyadh/i, /jeddah/i,
  /port/i, /airport/i, /seaport/i, /via /, /to /,
];

// ====== 工具函数 ======

function isSystemMessage(text) {
  if (!text || typeof text !== 'string') return false;
  if (text.trim().length === 0) return false;
  return SYSTEM_MSG_PATTERNS.some((p) => p.test(text));
}

function isEmojiOrSingleWord(text) {
  if (!text || typeof text !== 'string') return false;
  const trimmed = text.trim();
  if (trimmed.length === 0) return true;
  if (trimmed.length <= 3) return true;
  return EMOJI_SINGLE_PATTERNS.some((p) => p.test(trimmed));
}

function scanProductCodes(text) {
  if (!text || typeof text !== 'string') return [];
  const matches = text.match(PRODUCT_CODE_RE) || [];
  return [...new Set(matches.map((m) => m.toUpperCase()))];
}

function scanAddressKeywords(text) {
  if (!text || typeof text !== 'string') return false;
  return ADDRESS_KEYWORDS.some((re) => re.test(text));
}

function calcSilenceDays(lastContactTime) {
  if (!lastContactTime) return 999;
  const now = Date.now();
  const ts = typeof lastContactTime === 'number' ? lastContactTime : new Date(lastContactTime).getTime();
  if (isNaN(ts)) return 999;
  return Math.floor((now - ts) / 86400000);
}

function calcMessageDirection(messages) {
  if (!Array.isArray(messages) || messages.length === 0) return null;
  let sent = 0;
  let received = 0;
  for (const msg of messages) {
    if (msg.side === 'sent' || msg.latestMessageType === 'send') sent++;
    else if (msg.side === 'received' || msg.latestMessageType === 'received') received++;
  }
  const total = sent + received;
  return {
    total,
    sent,
    received,
    ratioFromUs: total > 0 ? (sent / total) : 0,
  };
}

function findLatestRealMessage(messages) {
  if (!Array.isArray(messages)) return null;
  for (let i = messages.length - 1; i >= 0; i--) {
    const msg = messages[i];
    const text = msg.text || msg.latestMessageContent || '';
    if (!isSystemMessage(text)) return msg;
  }
  return null;
}

// ====== 主处理函数 ======

function getCustomersFromData(data) {
  if (Array.isArray(data)) return data;
  if (data.customers) return data.customers;
  if (data.p0p1) return data.p0p1;
  if (data.results) return data.results;
  return [];
}

function processCustomer(customer) {
  const entry = { ...customer };
  const flags = {};
  const issues = [];

  const rawMsg = entry.latestMessageContent || '';
  const isSys = isSystemMessage(rawMsg);

  // 1. 系统消息检测
  flags.isLatestSystemMsg = isSys;
  if (isSys) {
    issues.push('latestMessageContent 是系统消息');
    // 尝试从消息列表中找真实消息
    if (Array.isArray(entry.messages)) {
      const real = findLatestRealMessage(entry.messages);
      if (real) {
        entry._replacedMessageContent = real.text || real.latestMessageContent || '';
        entry._replacedFromIndex = entry.messages.indexOf(real);
        flags.latestMsgReplaced = true;
      }
    }
  }

  // 2. 表情/单字检测
  const effectiveMsg = flags.latestMsgReplaced ? entry._replacedMessageContent : rawMsg;
  if (isEmojiOrSingleWord(effectiveMsg)) {
    flags.needLookback = true;
    issues.push('最后一条有效消息是表情/单字，需往前看');
  }

